import React, { useState } from 'react';
import PlayerList from '../components/PlayerList';

export default function Lobby({ socket, setRoomCode, setPlayerId }) {
  const [name, setName] = useState('');
  const [code, setCode] = useState('');
  const [mode, setMode] = useState(null); // 'create' | 'join'
  const [error, setError] = useState('');
  const [joined, setJoined] = useState(false);
  const [myRoomCode, setMyRoomCode] = useState(null);
  const [roomState, setRoomState] = useState(null);
  const [myPlayerId, setMyPlayerId] = useState(null);
  const [isHost, setIsHost] = useState(false);

  React.useEffect(() => {
    socket.on('room_state', (state) => {
      setRoomState(state);
      if (state.phase !== 'lobby') {
        setRoomCode(myRoomCode);
      }
    });
    return () => socket.off('room_state');
  }, [myRoomCode]);

  const handleCreate = () => {
    if (!name.trim()) return setError('Wpisz swój nick.');
    socket.emit('create_room', { name: name.trim() }, (res) => {
      if (res.error) return setError(res.error);
      setMyRoomCode(res.roomCode);
      setMyPlayerId(res.playerId);
      setPlayerId(res.playerId);
      setIsHost(true);
      setJoined(true);
      setError('');
    });
  };

  const handleJoin = () => {
    if (!name.trim()) return setError('Wpisz swój nick.');
    if (!code.trim()) return setError('Wpisz kod pokoju.');
    socket.emit('join_room', { name: name.trim(), roomCode: code.trim() }, (res) => {
      if (res.error) return setError(res.error);
      setMyRoomCode(res.roomCode);
      setMyPlayerId(res.playerId);
      setPlayerId(res.playerId);
      setIsHost(false);
      setJoined(true);
      setError('');
    });
  };

  const handleStart = () => {
    socket.emit('start_game', { roomCode: myRoomCode }, (res) => {
      if (res?.error) setError(res.error);
    });
  };

  if (joined && roomState) {
    return (
      <div className="card">
        <div style={{ textAlign: 'center', marginBottom: 24 }}>
          <span className="muted">Kod pokoju</span>
          <div style={{
            fontFamily: 'var(--font-head)',
            fontSize: '2.8rem',
            fontWeight: 800,
            letterSpacing: '0.2em',
            color: 'var(--accent2)',
            marginTop: 4
          }}>
            {myRoomCode}
          </div>
          <span className="muted" style={{ fontSize: '0.8rem' }}>Pokaż innym, żeby dołączyli</span>
        </div>

        <h3 style={{ marginBottom: 12 }}>Gracze ({roomState.players.length})</h3>
        <PlayerList players={roomState.players} />

        {error && <div className="error-msg">{error}</div>}

        {isHost ? (
          <div style={{ marginTop: 24 }}>
            <button
              className="btn btn-primary"
              style={{ width: '100%', fontSize: '1.1rem', padding: '14px' }}
              onClick={handleStart}
              disabled={roomState.players.length < 2}
            >
              {roomState.players.length < 2 ? 'Czekaj na graczy... (min. 2)' : '🚀 Rozpocznij grę'}
            </button>
          </div>
        ) : (
          <p className="muted" style={{ marginTop: 24, textAlign: 'center' }}>
            Czekaj, aż host rozpocznie grę...
          </p>
        )}
      </div>
    );
  }

  return (
    <div className="card">
      <div style={{ textAlign: 'center', marginBottom: 32 }}>
        <h1 style={{ color: 'var(--accent)', marginBottom: 8 }}>IMPOSTOR</h1>
        <p className="muted">Gra imprezowa dla znajomych</p>
      </div>

      {!mode ? (
        <div className="flex gap-12" style={{ flexDirection: 'column' }}>
          <input
            placeholder="Twój nick..."
            value={name}
            onChange={e => setName(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && mode === 'create' && handleCreate()}
            maxLength={20}
          />
          <div className="flex gap-12">
            <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => setMode('create')}>
              Stwórz pokój
            </button>
            <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setMode('join')}>
              Dołącz
            </button>
          </div>
          {error && <div className="error-msg">{error}</div>}
        </div>
      ) : mode === 'create' ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <input
            placeholder="Twój nick..."
            value={name}
            onChange={e => setName(e.target.value)}
            maxLength={20}
          />
          <button className="btn btn-primary" onClick={handleCreate}>Stwórz pokój</button>
          <button className="btn btn-secondary" onClick={() => setMode(null)}>Wróć</button>
          {error && <div className="error-msg">{error}</div>}
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <input
            placeholder="Twój nick..."
            value={name}
            onChange={e => setName(e.target.value)}
            maxLength={20}
          />
          <input
            placeholder="Kod pokoju..."
            value={code}
            onChange={e => setCode(e.target.value.toUpperCase())}
            maxLength={6}
            style={{ letterSpacing: '0.2em', fontWeight: 700 }}
          />
          <button className="btn btn-primary" onClick={handleJoin}>Dołącz do pokoju</button>
          <button className="btn btn-secondary" onClick={() => setMode(null)}>Wróć</button>
          {error && <div className="error-msg">{error}</div>}
        </div>
      )}
    </div>
  );
}
